import React, { useState } from 'react';
import { Mail, Lock, Eye, EyeOff, Globe, Sun, Moon } from 'lucide-react';
import { useApp, useAppActions } from '../context/AppContext';
import '../styles/globals.css';
import logo from '../assets/logo.png'

const Login: React.FC = () => {
  const { state } = useApp();
  const { setLogin, changeLanguage, changeTheme } = useAppActions();

  const [email, setEmail] = useState('admin@encontact.com');
  const [password, setPassword] = useState('admin123');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);


  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    // Simular autenticação
    setTimeout(() => {
      setLogin(true);
      setIsLoading(false);
    }, 1000);
  };

  const isFormValid = email.trim() !== '' && password.trim() !== '';

  return (
    <div 
      className="min-h-screen flex items-center justify-center p-4"
      style={{ backgroundColor: 'var(--color-background)' }}
    >
      <div className="w-full max-w-md">
        {/* Card de Login */}
        <div 
          className="card p-8 animate-scale-in"
          style={{
            backgroundColor: 'var(--color-surface)',
            borderColor: 'var(--color-border)'
          }}
        >
          {/* Header */}
          <div className="text-center mb-8">
            <div className="flex justify-center mb-4">
              <div className="w-16 h-16 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg">

              </div>
            </div>
            <h1 
              className="text-2xl font-bold mb-2"
              style={{ color: 'var(--color-text-primary)' }}
            >
              {state.language === 'pt' ? 'Bem-vindo ao enContact' : 'Welcome to enContact'}
            </h1>
            <p 
              className="text-sm"
              style={{ color: 'var(--color-text-secondary)' }}
            >
              {state.language === 'pt' 
                ? 'Sua plataforma de comunicação profissional' 
                : 'Your professional communication platform'
              }
            </p>
          </div>

          {/* Formulário */}
          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Campo Email */}
            <div>
              <label 
                htmlFor="email"
                className="block text-sm font-medium mb-2"
                style={{ color: 'var(--color-text-primary)' }}
              >
                {state.language === 'pt' ? 'E-mail' : 'Email'}
              </label>
              <div className="relative">
                <Mail 
                  size={18} 
                  className="absolute left-3 top-1/2 transform -translate-y-1/2 pointer-events-none"
                  style={{ color: 'var(--color-text-muted)' }}
                />
                <input
                  id="email"
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="input pl-10"
                  placeholder={state.language === 'pt' ? 'seu@email.com' : 'your@email.com'}
                  style={{
                    backgroundColor: 'var(--color-background)',
                    borderColor: 'var(--color-border)',
                    color: 'var(--color-text-primary)'
                  }}
                  required
                />
              </div>
            </div>

            {/* Campo Senha */}
            <div>
              <label 
                htmlFor="password"
                className="block text-sm font-medium mb-2"
                style={{ color: 'var(--color-text-primary)' }}
              >
                {state.language === 'pt' ? 'Senha' : 'Password'}
              </label>
              <div className="relative">
                <Lock 
                  size={18} 
                  className="absolute left-3 top-1/2 transform -translate-y-1/2 pointer-events-none"
                  style={{ color: 'var(--color-text-muted)' }}
                />
                <input
                  id="password"
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="input pl-10 pr-10"
                  placeholder={state.language === 'pt' ? 'Digite sua senha' : 'Enter your password'}
                  style={{
                    backgroundColor: 'var(--color-background)',
                    borderColor: 'var(--color-border)',
                    color: 'var(--color-text-primary)'
                  }}
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 transform -translate-y-1/2 pointer-events-none"
                  style={{ color: 'var(--color-text-muted)' }}
                >
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>

            {/* Botão de Login */}
            <button
              type="submit"
              disabled={!isFormValid || isLoading}
              className="btn btn-primary w-full btn-lg"
            >
              {isLoading ? (
                <div className="animate-spin w-5 h-5 border-2 border-white border-t-transparent rounded-full" />
              ) : (
                state.language === 'pt' ? 'Entrar' : 'Sign In'
              )}
            </button>
          </form>

          {/* Opções de Tema e Idioma */}
          <div className="flex items-center justify-between mt-6 pt-6 border-t" style={{ borderColor: 'var(--color-border)' }}>
            <button 
              onClick={changeLanguage} 
              className="btn btn-ghost btn-sm"
            >
              <Globe size={16} />
              <span className="uppercase">{state.language}</span>
            </button>

            <button 
              onClick={changeTheme} 
              className="btn btn-ghost btn-sm"
            >
              {state.theme === 'dark' ? <Sun size={16} /> : <Moon size={16} />}
            </button>
          </div>

          {/* Link para ajuda */}
          <div className="text-center mt-6">
            <button 
              className="text-sm hover:underline"
              style={{ color: 'var(--color-primary)', background: 'none', border: 'none', cursor: 'pointer' }}
            >
              {state.language === 'pt' ? 'Esqueceu a senha?' : 'Forgot password?'}
            </button>
          </div>
        </div>

        {/* Footer */}
        <div className="text-center mt-6">
          <p 
            className="text-xs"
            style={{ color: 'var(--color-text-muted)' }}
          >
            © 2024 enContact. {state.language === 'pt' ? 'Todos os direitos reservados.' : 'All rights reserved.'}
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;
